    13→static int
    14→nfp_devlink_fill_eth_port(struct nfp_port *port,
    15→			  struct nfp_eth_table_port *copy)
    16→{
    17→	struct nfp_eth_table_port *eth_port;
    18→
    19→	eth_port = __nfp_port_get_eth_port(port);
    20→	if (!eth_port)
    21→		return -EINVAL;
    22→
    23→	memcpy(copy, eth_port, sizeof(*eth_port));
    24→
    25→	return 0;
    26→}
